### Phase 2: Execution

#### **Target Path:** `Phantom_QA/ui/src/components/TelemetryWidget.jsx`

```javascript
// Phantom_QA/ui/src/components/TelemetryWidget.jsx

import React, { useState, useEffect } from 'react';
import './TelemetryWidget.css'; // Assuming a dedicated CSS file for styling

const TelemetryWidget = () => {
  const [uptime, setUptime] = useState('00h 00m 00s');
  const [activeAgents, setActiveAgents] = useState(0);
  const [dataThroughput, setDataThroughput] = useState('0 KB/s');

  useEffect(() => {
    // Simulate real-time data updates
    const interval = setInterval(() => {
      // Simulate uptime
      const now = new Date();
      const start = new Date(now.getFullYear(), now.getMonth(), now.getDate(), now.getHours() - 1, now.getMinutes() - 5, now.getSeconds() - 30); // Started 1h 5m 30s ago
      const diff = now.getTime() - start.getTime();
      const hours = Math.floor(diff / (1000 * 60 * 60)).toString().padStart(2, '0');
      const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60)).toString().padStart(2, '0');
      const seconds = Math.floor((diff % (1000 * 60)) / 1000).toString().padStart(2, '0');
      setUptime(`${hours}h ${minutes}m ${seconds}s`);

      // Simulate active agents (random between 5 and 15)
      setActiveAgents(Math.floor(Math.random() * 11) + 5);

      // Simulate data throughput (random between 100 KB/s and 500 KB/s)
      setDataThroughput(`${(Math.random() * 400 + 100).toFixed(0)} KB/s`);
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="telemetry-widget" {/* Telemetry Widget */} id="live-telemetry">
      <h3>Live Telemetry</h3>
      <div className="telemetry-data">
        <div className="data-item">
          <span className="label">Uptime:</span>
          <span className="value">{uptime}</span>
        </div>
        <div className="data-item">
          <span className="label">Active Agents:</span>
          <span className="value">{activeAgents}</span>
        </div>
        <div className="data-item">
          <span className="label">Data Throughput:</span>
          <span className="value">{dataThroughput}</span>
        </div>
      </div>
      <p className="status-indicator">
        <span className="dot online"></span> Operational
      </p>
    </div>
  );
};

export default TelemetryWidget;
```

